typedef struct { uint64_t hi; uint64_t lo; } uint128_t;
unsigned parity128(uint128_t x) {
  uint64_t v = x.hi ^ x.lo;
  v ^= v >> 32;
  v ^= v >> 16;
  v ^= v >> 8;
  v ^= v >> 4;
