typedef struct { uint64_t hi; uint64_t lo; } uint128;
static inline uint64_t popcount64(uint64_t x){
  x = x - ((x >> 1) & 0x5555555555555555ULL);
  x = (x & 0x3333333333333333ULL) + ((x >> 2) & 0x3333333333333333ULL);
